let currentLang = localStorage.getItem('tribu_lang') || 'es';

function t(key) {
  return (LANGS[currentLang] && LANGS[currentLang][key]) ||
         (LANGS['es'] && LANGS['es'][key]) || key;
}

function applyLang() {
  document.querySelectorAll('[data-i18n]').forEach(el => {
    const k = el.getAttribute('data-i18n');
    const v = t(k);
    if ((el.tagName === 'INPUT' || el.tagName === 'TEXTAREA') && el.hasAttribute('placeholder')) {
      el.placeholder = v;
    } else {
      el.textContent = v;
    }
  });
  document.querySelectorAll('[data-i18n-ph]').forEach(el => {
    el.placeholder = t(el.getAttribute('data-i18n-ph'));
  });
  const cl = document.getElementById('currentLang');
  if (cl) cl.textContent = currentLang.toUpperCase();
  document.documentElement.lang = currentLang;
  const titleEl = document.querySelector('[data-i18n-title]');
  if (titleEl) document.title = t(titleEl.getAttribute('data-i18n-title'));
}

function setLang(lang) {
  currentLang = lang;
  localStorage.setItem('tribu_lang', lang);
  applyLang();
  const lm = document.getElementById('langMenu');
  if (lm) lm.classList.remove('open');
}

function toggleLangMenu() {
  const lm = document.getElementById('langMenu');
  if (lm) lm.classList.toggle('open');
}

document.addEventListener('click', e => {
  if (!e.target.closest('.lang-selector')) {
    const lm = document.getElementById('langMenu');
    if (lm) lm.classList.remove('open');
  }
});

// â”€â”€ Auth helpers â”€â”€
function getUser()    { try { return JSON.parse(localStorage.getItem('tribu_user')); } catch { return null; } }
function getToken()   { return localStorage.getItem('tribu_token'); }
function isLoggedIn() { return !!getToken(); }
function saveAuth(token, user) {
  localStorage.setItem('tribu_token', token);
  localStorage.setItem('tribu_user', JSON.stringify(user));
}
function logout() {
  localStorage.removeItem('tribu_token');
  localStorage.removeItem('tribu_user');
  window.location = '/login';
}

// â”€â”€ API helper â”€â”€
async function api(method, path, body, auth = true) {
  const headers = { 'Content-Type': 'application/json' };
  if (auth) {
    const token = getToken();
    if (token) headers['Authorization'] = 'Bearer ' + token;
  }
  const opts = { method, headers };
  if (body && method !== 'GET') opts.body = JSON.stringify(body);
  const r = await fetch('/api' + path, opts);
  const data = await r.json().catch(() => ({}));
  if (!r.ok) throw new Error(data.error || 'Error ' + r.status);
  return data;
}

// â”€â”€ Nav auth state â”€â”€
function updateNavAuth() {
  const loginBtn  = document.getElementById('navLoginBtn');
  const dashBtn   = document.getElementById('navDashBtn');
  const logoutBtn = document.getElementById('navLogoutBtn');
  if (isLoggedIn()) {
    if (loginBtn)  loginBtn.style.display  = 'none';
    if (dashBtn)   dashBtn.style.display   = 'inline-flex';
    if (logoutBtn) logoutBtn.style.display = 'inline-flex';
  } else {
    if (loginBtn)  loginBtn.style.display  = 'inline-flex';
    if (dashBtn)   dashBtn.style.display   = 'none';
    if (logoutBtn) logoutBtn.style.display = 'none';
  }
}

// â”€â”€ Scroll nav â”€â”€
window.addEventListener('scroll', () => {
  const nav = document.getElementById('mainNav');
  if (!nav || nav.classList.contains('nav-solid')) return;
  nav.classList.toggle('scrolled', window.scrollY > 60);
});

// â”€â”€ Helpers â”€â”€
function formatDate(dateStr) {
  const d = new Date(dateStr);
  return d.toLocaleDateString(currentLang === 'ja' ? 'ja-JP' : currentLang, { year: 'numeric', month: 'short', day: 'numeric' });
}

function getYoutubeId(url) {
  if (!url) return null;
  const m = url.match(/(?:youtu\.be\/|youtube\.com\/(?:watch\?v=|embed\/|v\/))([\w-]{11})/);
  return m ? m[1] : null;
}

function catBadgeHTML(cat) {
  const icons = { farming:'fa-tractor', gardening:'fa-seedling', beekeeping:'fa-bug', medicinal:'fa-mortar-pestle', preservation:'fa-jar', building:'fa-house', hunting:'fa-fish', tools:'fa-hammer', survival:'fa-fire', adventures:'fa-mountain' };
  const icon = icons[cat] || 'fa-leaf';
  return `<span class="cat-badge badge-${cat}"><i class="fas ${icon}"></i> ${t('cat_' + cat)}</span>`;
}

document.addEventListener('DOMContentLoaded', () => {
  applyLang();
  updateNavAuth();
});
